function RootDiagram({ onHoverChange }: { onHoverChange: (i: number | null) => void }) {
  const [started, setStarted] = useState(false);
  const [hovered, setHovered] = useState<number | null>(null);

  useEffect(() => {
    const t = setTimeout(() => setStarted(true), 400);
    return () => clearTimeout(t);
  }, []);

  const handleHover = (i: number | null) => {
    setHovered(i);
    onHoverChange(i);
  };

  return (
    <div className="relative hidden w-full max-w-5xl md:block">
      <div className="relative w-full overflow-hidden">
        <svg
          viewBox={`${VB_X} ${VB_Y} ${VB_W} ${VB_H}`}
          className="block w-full"
          aria-hidden="true"
        >
          <defs>
            {/* Adelgaza la silueta ~4px en todos los bordes */}
            <filter id="tree-thin" x="-3%" y="-2%" width="106%" height="104%">
              <feMorphology operator="erode" radius="4" result="eroded" />
              <feGaussianBlur stdDeviation="0.8" in="eroded" />
            </filter>
          </defs>

          {/* Árbol: escalado 2.1× y adelgazado con filtro morfológico */}
          <g transform={TREE_TRANSFORM} filter="url(#tree-thin)">
            <path d={TREE_PATH} fill="#c7a84b" fillOpacity={0.55} />
          </g>

          {/* Punto + nombre en cada root tip */}
          {ROOTS.map((root, i) => (
            <g key={root.name}>
              <circle
                cx={root.cx}
                cy={root.cy}
                r={hovered === i ? 5 : 3}
                fill="#c7a84b"
                style={{
                  opacity: started ? (hovered === i ? 1 : 0.65) : 0,
                  transition: `opacity 0.3s ease ${root.delay + 2.3}s`,
                }}
              />
              <text
                x={root.cx}
                y={root.cy + 20}
                textAnchor="middle"
                fill={hovered === i ? "#c7a84b" : "#fbf9f4"}
                fontSize={16}
                fontFamily="'Cormorant Garamond', serif"
                style={{
                  opacity: started ? 1 : 0,
                  transition: `opacity 0.5s ease ${root.delay + 2.3}s, fill 0.3s ease`,
                }}
              >
                {root.name}
              </text>
              <text
                x={root.cx}
                y={root.cy + 34}
                textAnchor="middle"
                fill="#c7a84b"
                fontSize={10}
                fontFamily="system-ui, sans-serif"
                letterSpacing={2}
                style={{
                  opacity: started ? 0.5 : 0,
                  transition: `opacity 0.5s ease ${root.delay + 2.45}s`,
                }}
              >
                {root.tag}
              </text>
            </g>
          ))}
        </svg>

        {/* Cortina: se retira de abajo hacia arriba (raíces primero) */}
        <motion.div
          className="pointer-events-none absolute inset-0"
          style={{ backgroundColor: "#00101f", transformOrigin: "top center" }}
          initial={{ scaleY: 1 }}
          animate={started ? { scaleY: 0 } : { scaleY: 1 }}
          transition={{ duration: 2.8, ease: [0.15, 0.55, 0.35, 1] }}
        />
      </div>

      {/* Zonas de hover invisibles */}
      {ROOTS.map((root, i) => (
        <div
          key={root.name}
          className="absolute cursor-default"
          style={{
            left: `${((root.cx - VB_X) / VB_W) * 100}%`,
            top: `${((root.cy - VB_Y) / VB_H) * 100}%`,
            transform: "translateX(-50%)",
            width: 140,
            height: 65,
            zIndex: 2,
          }}
          onMouseEnter={() => handleHover(i)}
          onMouseLeave={() => handleHover(null)}
        />
      ))}
    </div>
  );
}

